INSERT INTO `knowledge_point` (`id`, `content`, `create_time`, `description`, `difficulty`, `enabled`, `keywords`, `name`, `order_num`, `update_time`, `course_id`) VALUES (1,'','2026-06-05 03:13:09.541581','高等数据结构','HARD',0x01,'','线段树',0,'2026-06-05 03:13:09.541581',1),(2,'','2026-06-05 03:13:38.662620','高等数据结构','HARD',0x01,'','树状数组',0,'2026-06-05 03:13:38.662620',1),(3,'','2026-06-05 03:13:58.520562','高等数据结构','HARD',0x01,'','树套树',0,'2026-06-05 03:13:58.520562',1),(4,'','2026-06-05 03:14:10.917769','初等数据结构','EASY',0x01,'','链表',0,'2026-06-05 03:14:10.917769',1),(5,'','2026-06-05 03:14:51.084071','简单数据结构','EASY',0x01,'','优先队列',0,'2026-06-05 03:14:51.084071',1),(6,'','2026-06-05 03:15:03.563881','中级算法','MEDIUM',0x01,'','并查集',0,'2026-06-05 03:15:03.563881',1),(7,'详细的知识点内容...','2026-06-06 00:32:06.786023','这是一个示例知识点的描述','MEDIUM',0x01,'关键词1,关键词2','示例知识点',1,'2026-06-06 00:32:06.786023',1),(8,NULL,'2026-06-06 00:32:06.822743','必填字段标有*号','MEDIUM',0x01,NULL,'说明：',2,'2026-06-06 00:32:06.822743',1),(9,'理解 O、Ω、Θ 记号；能够分析顺序、分支、循环、递归程序的复杂度；区分最好、最坏和平均情况。','2026-06-07 03:46:28.568286','掌握时间复杂度、空间复杂度和渐进符号的基本分析方法。','EASY',0x01,'时间复杂度,空间复杂度,大O,渐进分析','算法复杂度分析',1,'2026-06-07 03:46:28.568286',1),(10,'掌握顺序表的查找、插入、删除、扩容与下标访问；分析各操作的时间复杂度和适用场景。','2026-06-07 03:46:28.593288','理解线性表抽象数据类型及数组顺序表实现。','EASY',0x01,'线性表,顺序表,数组,动态数组','线性表与顺序存储',2,'2026-06-07 03:46:28.593288',1),(11,'理解指针/引用链接关系；能够实现链表插入、删除、查找、反转、合并等常见操作。','2026-06-07 03:46:28.599284','掌握单链表、双向链表和循环链表的结构与操作。','MEDIUM',0x01,'单链表,双向链表,循环链表,指针','链表结构',3,'2026-06-07 03:46:28.599284',1),(12,'掌握顺序栈和链栈实现；应用于括号匹配、表达式求值、函数调用、深度优先遍历。','2026-06-07 03:46:28.606284','理解后进先出结构及其典型应用。','EASY',0x01,'栈,LIFO,括号匹配,表达式求值','栈',4,'2026-06-07 03:46:28.606284',1),(13,'掌握队列基本操作、循环队列判空判满、链队列实现，以及 BFS 等应用场景。','2026-06-07 03:46:28.612284','理解先进先出结构、循环队列和双端队列。','EASY',0x01,'队列,FIFO,循环队列,双端队列,BFS','队列',5,'2026-06-07 03:46:28.612284',1),(14,'掌握朴素匹配、KMP 的 next 数组思想，理解前缀后缀和失配跳转。','2026-06-07 03:46:28.618286','理解字符串存储和经典模式匹配算法。','MEDIUM',0x01,'字符串,KMP,模式匹配,next数组','串与模式匹配',6,'2026-06-07 03:46:28.618286',1),(15,'能够编写递归算法，分析递归复杂度；理解归并排序、快速排序、二分查找等分治思想。','2026-06-07 03:46:28.626284','掌握递归建模、递归出口和分治算法设计。','MEDIUM',0x01,'递归,分治,二分查找,主定理','递归与分治',7,'2026-06-07 03:46:28.626284',1),(16,'掌握树的表示方法、父子兄弟关系、树和二叉树之间的转换。','2026-06-07 03:46:28.632288','理解树、森林、节点度、层次、高度等基本概念。','EASY',0x01,'树,森林,节点,高度,度','树的基本概念',8,'2026-06-07 03:46:28.632288',1),(17,'能够用递归和非递归方式实现遍历；理解遍历序列恢复二叉树的条件。','2026-06-07 03:46:28.638289','掌握二叉树的先序、中序、后序和层序遍历。','MEDIUM',0x01,'二叉树,先序,中序,后序,层序','二叉树遍历',9,'2026-06-07 03:46:28.638289',1),(18,'掌握插入、查找、删除，分析平均和最坏复杂度，理解退化为链表的问题。','2026-06-07 03:46:28.644284','理解 BST 的有序性和动态查找操作。','MEDIUM',0x01,'BST,二叉搜索树,查找,删除','二叉搜索树',10,'2026-06-07 03:46:28.644284',1),(19,'掌握 AVL 旋转思想、红黑树性质和插入调整的大致流程，理解其在映射和集合中的应用。','2026-06-07 03:46:28.650285','理解平衡树维护高度的核心思想。','HARD',0x01,'AVL,红黑树,旋转,平衡树','平衡二叉树与红黑树',11,'2026-06-07 03:46:28.650285',1),(20,'理解大根堆、小根堆、上滤、下滤、建堆和堆排序；能够用堆实现 TopK 问题。','2026-06-07 03:46:28.657286','掌握堆结构及优先级调度应用。','MEDIUM',0x01,'堆,优先队列,堆排序,TopK','堆与优先队列',12,'2026-06-07 03:46:28.657286',1),(21,'掌握开放定址法、链地址法、再哈希；分析平均 O(1) 查询的条件和失效场景。','2026-06-07 03:46:28.663286','理解散列函数、冲突处理和装载因子。','MEDIUM',0x01,'哈希表,散列函数,冲突,装载因子','哈希表',13,'2026-06-07 03:46:28.663286',1),(22,'掌握邻接矩阵、邻接表、无向图、有向图、带权图的表示和复杂度差异。','2026-06-07 03:46:28.669286','理解图的顶点、边、路径、连通性及存储结构。','MEDIUM',0x01,'图,邻接矩阵,邻接表,有向图,无向图','图的基本概念与存储',14,'2026-06-07 03:46:28.669286',1),(23,'能够用 DFS/BFS 解决连通分量、路径搜索、拓扑层次等问题，并分析复杂度。','2026-06-07 03:46:28.675289','掌握深度优先搜索和广度优先搜索。','MEDIUM',0x01,'DFS,BFS,图遍历,连通分量','图的遍历',15,'2026-06-07 03:46:28.675289',1),(24,'掌握 Dijkstra、Bellman-Ford、Floyd 算法的适用条件、状态转移和复杂度。','2026-06-07 03:46:28.680292','理解单源和多源最短路径问题。','HARD',0x01,'Dijkstra,Bellman-Ford,Floyd,最短路径','最短路径算法',16,'2026-06-07 03:46:28.680292',1),(25,'理解 Kruskal 和 Prim 算法；掌握并查集在 Kruskal 中的作用。','2026-06-07 03:46:28.686291','掌握连通带权无向图的最小生成树算法。','HARD',0x01,'MST,Kruskal,Prim,并查集','最小生成树',17,'2026-06-07 03:46:28.686291',1),(26,'比较插入、选择、冒泡、希尔、归并、快速、堆排序的思想、复杂度和稳定性。','2026-06-07 03:46:28.691289','掌握常见内部排序算法及稳定